const LEVEL_META = {
  A1: {name:'Beginner French', desc:'Basic introductions, simple sentences, everyday words and survival communication.'},
  A2: {name:'Elementary French', desc:'Everyday communication, simple past/future, travel, health, housing and opinions.'},
  B1: {name:'Independent French', desc:'Everyday situations, work, travel, narration, opinions and connected sentences.'},
  B2: {name:'Upper-intermediate French', desc:'Nuance, complex texts, viewpoints, arguments, formal language and fluency.'},
  C1: {name:'Advanced French', desc:'Precise argumentation, synthesis, register, professional and academic discourse.'},
  C2: {name:'Mastery French', desc:'Subtle meaning, rhetoric, implicit language, style control and high-level mediation.'}
};
const STORAGE_KEY = 'frenchA1C2AppStateV11';
const saved = JSON.parse(localStorage.getItem(STORAGE_KEY) || '{}');
const state = {
  level: saved.level || '',
  current: saved.current || 1,
  tab: saved.tab || 'learn',
  completed: saved.completed || {},
  scores: saved.scores || {},
  theme: saved.theme || localStorage.getItem('theme') || 'dark',
  reviewMode: saved.reviewMode || false
};
Object.keys(DATA).forEach(level => {
  if (!Array.isArray(state.completed[level])) state.completed[level] = [];
  if (!state.scores[level]) state.scores[level] = {};
});
const $ = (selector, root=document) => root.querySelector(selector);
const $$ = (selector, root=document) => Array.from(root.querySelectorAll(selector));
const tg = window.Telegram && window.Telegram.WebApp ? window.Telegram.WebApp : null;
function initTelegram(){ try { tg?.ready(); tg?.expand(); } catch(e) {} }
function vibrate(){ try { tg?.HapticFeedback?.selectionChanged?.(); } catch(e) {} }
function saveState(){ localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); localStorage.setItem('theme', state.theme); }
function setTheme(theme){ state.theme = theme; document.documentElement.setAttribute('data-theme', theme); $('#themeToggle').textContent = theme === 'dark' ? '🌙' : '☀️'; saveState(); }
function escapeHtml(value=''){ return String(value).replace(/[&<>"]/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[ch] || ch)); }
function normalizeAnswer(value=''){ return value.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[’']/g,"'").replace(/[^a-z0-9' ]/gi,'').replace(/\s+/g,' ').trim(); }
function showToast(message){ const old=$('.toast'); if(old) old.remove(); const t=document.createElement('div'); t.className='toast'; t.textContent=message; document.body.appendChild(t); setTimeout(()=>t.remove(),2600); }
let slowSpeechTimer = null;
function speakFrench(text, rate=0.86){
  if(!('speechSynthesis' in window)){ showToast('Text-to-speech is not available in this browser.'); return; }
  window.speechSynthesis.cancel();
  if(slowSpeechTimer){ clearTimeout(slowSpeechTimer); slowSpeechTimer = null; }
  const isSlow = Number(rate) <= 0.5;
  const voices=window.speechSynthesis.getVoices();
  const fr=voices.find(v => v.lang && v.lang.toLowerCase().startsWith('fr'));
  const speakOne = (chunk, r=0.82, onend=null) => {
    const u=new SpeechSynthesisUtterance(chunk);
    u.lang='fr-FR';
    u.rate=r;
    u.pitch=1;
    if(fr) u.voice=fr;
    if(onend) u.onend=onend;
    window.speechSynthesis.speak(u);
  };
  if(!isSlow){ speakOne(text, Number(rate || 0.86)); return; }
  // True slow mode: short chunks with pauses. This works better in Telegram/iOS, where rate alone may be ignored.
  const chunks = String(text)
    .replace(/([,;:])/g, '$1|')
    .replace(/([.!?])/g, '$1|')
    .split('|')
    .map(x=>x.trim())
    .filter(Boolean);
  let i=0;
  const next=()=>{
    if(i>=chunks.length) return;
    const chunk=chunks[i++];
    speakOne(chunk, 0.42, ()=>{ slowSpeechTimer=setTimeout(next, 520); });
  };
  next();
}
function getLessons(){ return DATA[state.level] || []; }
function getLesson(){ return getLessons().find(l => l.id === state.current) || getLessons()[0]; }
function isCompleted(level,id){ return (state.completed[level] || []).includes(id); }
function highestUnlocked(level){ const completed = state.completed[level] || []; if(!completed.length) return 1; return Math.min(DATA[level].length, Math.max(...completed)+1); }
function canOpen(level,id){ return state.reviewMode || id <= highestUnlocked(level); }
function markCompleted(level,id){ if(!state.completed[level].includes(id)) state.completed[level].push(id); state.completed[level].sort((a,b)=>a-b); }
function totalScore(level){ const scores = state.scores[level] || {}; let correct=0,total=0; Object.values(scores).forEach(s=>{ if(s && s.completed){ correct += Number(s.correct||0); total += Number(s.total||0); } }); return {correct,total}; }
function nextExamDistance(lessonId){ const exams=[7,14,21,28,35,42,49,50]; const next=exams.find(x => x>=lessonId); return next ? next-lessonId : null; }
function setupSelector(){ const sel=$('#lessonSelect'); sel.innerHTML=''; if(!state.level){ const o=document.createElement('option'); o.textContent='Choose a level'; sel.appendChild(o); return; } const unlocked=highestUnlocked(state.level); getLessons().forEach(lesson=>{ const o=document.createElement('option'); o.value=lesson.id; o.textContent=`${state.level} Class ${lesson.id}${(!state.reviewMode && lesson.id>unlocked)?' 🔒':''}`; o.disabled=(!state.reviewMode && lesson.id>unlocked); sel.appendChild(o); }); sel.value=String(state.current); }
function bindStaticActions(){
  $('#themeToggle').addEventListener('click',()=>setTheme(state.theme==='dark'?'light':'dark'));
  $('#prevBtn').addEventListener('click',()=>{ if(!state.level) return; state.current=Math.max(1,state.current-1); state.tab='learn'; saveState(); setupSelector(); render(); });
  $('#nextBtn').addEventListener('click',()=>{ if(!state.level) return; if(!isCompleted(state.level,state.current)){ showToast('Finish the current class practice before going to the next class.'); state.tab='practice'; render(); return; } state.current=Math.min(getLessons().length,state.current+1); state.tab='learn'; saveState(); setupSelector(); render(); });
  $('#lessonSelect').addEventListener('change',e=>{ if(!state.level) return; const id=Number(e.target.value); if(!canOpen(state.level,id)){ showToast('This class is locked. Finish the previous class first.'); setupSelector(); return; } state.current=id; state.tab='learn'; saveState(); render(); });
  document.addEventListener('focusin', e=>{ if(e.target.matches('.fill-input')) $('#bottomNav')?.classList.add('typing-hidden'); });
  document.addEventListener('focusout', e=>{ if(e.target.matches('.fill-input')) setTimeout(()=>$('#bottomNav')?.classList.remove('typing-hidden'), 180); });
  let codeBuffer='';
  document.addEventListener('keydown', e=>{ codeBuffer=(codeBuffer + e.key).slice(-4); if(codeBuffer==='2022') activateReviewMode(); });
}
function activateReviewMode(){ state.reviewMode=true; saveState(); setupSelector(); render(); showToast('Review mode unlocked. All classes are open.'); }
function render(){ if(!state.level || !DATA[state.level]) renderLevelChoice(); else renderLesson(); }
function renderLevelChoice(){
  $('#progressLabel').textContent='Choose your level'; $('#lessonTitle').textContent='French A1-C2'; $('#progressFill').style.width='0%'; $('#totalScore').textContent='Total score: 0 / 0'; $('#bottomNav').classList.add('hidden');
  const levels=Object.entries(LEVEL_META);
  $('#app').innerHTML=`<section class="lesson-card level-choice"><h2>Which level do you want to practise?</h2><p class="muted">Choose one CEFR level. Each level has 50 classes. Normal mode unlocks one class at a time.</p><div class="teacher-code"><input id="teacherCodeInput" type="password" inputmode="numeric" placeholder="Teacher review code" maxlength="4" /><button class="ghost-btn" id="teacherCodeBtn" type="button">Unlock review mode</button>${state.reviewMode ? '<span class="review-on">Review mode active</span>' : ''}</div><div class="level-grid">${levels.map(([code,meta])=>`<button class="level-card" data-level="${code}" type="button"><span class="level-badge">${code}</span><strong>${meta.name}</strong><span>${meta.desc}</span><small>${totalScore(code).correct} / ${totalScore(code).total} points saved</small></button>`).join('')}</div></section>`;
  $('#teacherCodeBtn')?.addEventListener('click',()=>{ if($('#teacherCodeInput').value.trim()==='2022') activateReviewMode(); else showToast('Code not valid.'); });
  $('#teacherCodeInput')?.addEventListener('keydown',e=>{ if(e.key==='Enter'){ if(e.currentTarget.value.trim()==='2022') activateReviewMode(); else showToast('Code not valid.'); } });
  $$('[data-level]').forEach(btn=>btn.addEventListener('click',()=>{ state.level=btn.dataset.level; state.current=Math.min(Number(state.current||1), highestUnlocked(state.level)); state.current=Number(localStorage.getItem(`currentLesson_${state.level}`) || state.current || 1); if(!canOpen(state.level,state.current)) state.current=highestUnlocked(state.level); state.tab='learn'; saveState(); setupSelector(); render(); }));
}
function renderLesson(){
  $('#bottomNav').classList.remove('hidden'); const lesson=getLesson(); if(!lesson){ renderLevelChoice(); return; }
  const total=getLessons().length; const score=totalScore(state.level); $('#totalScore').textContent=`Total score: ${score.correct} / ${score.total}`;
  $('#progressLabel').textContent=`${state.level} Class ${lesson.id} of ${total}${isCompleted(state.level,lesson.id)?' · completed':''}${state.reviewMode?' · review mode':''}`; $('#lessonTitle').textContent=lesson.title; $('#progressFill').style.width=`${Math.round((lesson.id/total)*100)}%`;
  const tpl=$('#lessonTemplate').content.cloneNode(true); tpl.querySelector('[data-field="classPill"]').textContent=`${state.level} · Class ${lesson.id}`; tpl.querySelector('[data-field="title"]').textContent=lesson.title; tpl.querySelector('[data-field="objective"]').textContent=lesson.objective || '';
  const examTab=tpl.querySelector('[data-tab="exam"]'); if(!lesson.exam || !lesson.exam.length){ const d=nextExamDistance(lesson.id); examTab.textContent=d===null?'Exam later':`Exam in ${d} class${d===1?'':'es'}`; examTab.disabled=true; examTab.classList.add('disabled'); }
  tpl.querySelector('#changeLevelBtn').addEventListener('click',()=>{ state.level=''; saveState(); setupSelector(); render(); });
  $$('.tab',tpl).forEach(tab=>{ tab.classList.toggle('active',tab.dataset.tab===state.tab); tab.addEventListener('click',()=>{ if(tab.disabled) return; state.tab=tab.dataset.tab; saveState(); render(); setTimeout(()=>document.getElementById(`${state.tab}Section`)?.scrollIntoView({behavior:'smooth',block:'start'}),80); }); });
  $('#app').innerHTML=''; $('#app').appendChild(tpl); renderTab(lesson); setupSelector();
}
function getRuleParts(lesson){ const fr=(lesson.rule||[]).find(x=>x.startsWith('Explication simple en français:'))||''; const en=(lesson.rule||[]).find(x=>x.startsWith('English explanation:'))||''; return {fr:fr.replace('Explication simple en français:','').trim(), en:en.replace('English explanation:','').trim()}; }
function renderTab(lesson){ const c=$('#tabContent'); c.innerHTML=renderAllSections(lesson); bindDynamicActions(c,lesson); }
function renderAllSections(lesson){ return `<div id="learnSection" class="section-anchor">${renderLearn(lesson)}</div><div id="sentencesSection" class="section-anchor">${renderSentences(lesson)}</div><div id="practiceSection" class="section-anchor">${renderPractice(lesson)}</div>${lesson.exam&&lesson.exam.length?`<div id="examSection" class="section-anchor">${renderExam(lesson)}</div>`:''}`; }
function renderLearn(lesson){ const rule=getRuleParts(lesson); return `<article class="lesson-card"><h3 class="section-title"><span>🔁</span> Refresh the previous class</h3><ul class="review-list">${(lesson.review||[]).map(x=>`<li>${escapeHtml(x)}</li>`).join('')}</ul></article>
<article class="lesson-card"><h3 class="section-title"><span>🧠</span> Rule of the day</h3><div class="rule-box"><strong>Explication simple en français</strong><p>${escapeHtml(rule.fr)}</p><div class="rule-listen"><button class="speech-btn" type="button" data-speak="${escapeHtml(rule.fr)}" data-rate="0.86">🔊 Listen</button><button class="speech-btn slow-btn" type="button" data-speak="${escapeHtml(rule.fr)}" data-rate="0.5">🐢 Slow 0.5x</button></div><strong>English explanation</strong><p>${escapeHtml(rule.en)}</p></div></article>
<article class="lesson-card"><h3 class="section-title"><span>📚</span> Vocabulary of the day</h3><p class="muted">New words and useful chunks for this class. Previous vocabulary may still appear in practice.</p><ul class="vocab-list">${(lesson.vocabulary||[]).map(v=>`<li>${escapeHtml(v)}</li>`).join('')}</ul></article>`; }
function renderSentences(lesson){ return `<article class="lesson-card"><h3 class="section-title"><span>🔊</span> Sentence bank</h3><p class="muted">Try to translate each English sentence by yourself first. After trying, tap the blurred French translation to check if you were correct. Once revealed, you can listen to the pronunciation at normal speed or slow 0.5x speed.</p><div class="sentence-list">${lesson.sentences.map((s,i)=>`<div class="sentence-row reveal-row"><div class="english">${i+1}. ${escapeHtml(s.en)}</div><button class="french blurred-translation" type="button" data-reveal-sentence>${escapeHtml(s.fr)}</button><div class="sentence-actions reveal-actions" hidden><button class="speech-btn" type="button" data-speak="${escapeHtml(s.fr)}" data-rate="0.86">🔊 Listen</button><button class="speech-btn slow-btn" type="button" data-speak="${escapeHtml(s.fr)}" data-rate="0.5">🐢 Slow 0.5x</button></div></div>`).join('')}</div></article>`; }
function insertMistakes(fr){
  const repls=[
    [/\bJe suis\b/,'Je es'], [/\bJe vais\b/,'Je va'], [/\bJ'ai\b/,'Je ai'], [/\bTu es\b/,'Tu est'], [/\bIl est\b/,'Il sont'], [/\bElle est\b/,'Elle sont'], [/\bNous sommes\b/,'Nous est'], [/\bNous avons\b/,'Nous a'], [/\bIls sont\b/,'Ils est'], [/\bIls ont\b/,'Ils a'], [/\bElle a\b/,'Elle ont'],
    [/\ble\b/i,'la'], [/\bla\b/i,'le'], [/\bun\b/i,'une'], [/\bune\b/i,'un'], [/\bdes\b/i,'de'], [/\bdu\b/i,'de la'], [/\bde la\b/i,'du'], [/\bau\b/i,'à le'], [/\baux\b/i,'à les'],
    [/\bpas\b/i,'jamais'], [/\bplus\b/i,'pas'], [/\bque\b/i,'qui'], [/\bqui\b/i,'que'], [/\bsera\b/i,'serait'], [/\bserait\b/i,'sera'], [/\bavait\b/i,'aura'], [/\bdevrait\b/i,'doit'], [/\bpour\b/i,'par'], [/\bavec\b/i,'sans'], [/\bdans\b/i,'sur'], [/\bà\b/i,'de'], [/\bde\b/i,'à']
  ];
  const out=[];
  for(const [pat,rep] of repls){ if(pat.test(fr)){ const v=fr.replace(pat,rep); if(v!==fr && !out.includes(v)) out.push(v); } }
  if(/\bne\b/.test(fr) && /\bpas\b/.test(fr)){ const v=fr.replace(/\bne\b\s*/,''); if(v!==fr && !out.includes(v)) out.push(v); }
  return out;
}
function subjectDistractor(fr){
  const pairs=[['Je ','Tu '],['Tu ','Je '],['Il ','Ils '],['Elle ','Elles '],['Nous ','Je '],['Vous ','Tu '],['Ils ','Il '],['Elles ','Elle '],['J’','Tu '],["J'",'Tu ']];
  for(const [a,b] of pairs){ if(fr.startsWith(a)) return b + fr.slice(a.length); }
  return '';
}
function swapTwoWords(fr){ const parts=splitTokens(fr); if(parts.length<4) return ''; const i=Math.min(2, parts.length-3); const copy=[...parts]; [copy[i],copy[i+1]]=[copy[i+1],copy[i]]; return copy.join(' ').replace(/\s+([?.!,;:])/g,'$1'); }
function makeChoiceOptions(sentence,i){ const correct=sentence.fr; const chosen=[]; const add=v=>{ if(v && normalizeAnswer(v)!==normalizeAnswer(correct) && !chosen.some(x=>normalizeAnswer(x)===normalizeAnswer(v))) chosen.push(v); };
  insertMistakes(correct).forEach(add);
  add(subjectDistractor(correct));
  add(swapTwoWords(correct));
  if(chosen.length<2 && correct.includes(',')) add(correct.replace(',', ''));
  if(chosen.length<2 && !correct.includes(' ne ')) add(correct.replace(/\b(est|sont|a|ont|va|vont|fait|font|sera|seront|peut|peuvent)\b/i, m=>m==='est'?'sont':m==='sont'?'est':m==='a'?'ont':m==='ont'?'a':m==='va'?'vont':m==='vont'?'va':'est'));
  if(chosen.length<2){ const parts=splitTokens(correct); if(parts.length>2){ parts.splice(Math.max(1,parts.length-2),0,'pas'); add(parts.join(' ').replace(/\s+([?.!,;:])/g,'$1')); } }
  while(chosen.length<2){ const parts=splitTokens(correct); if(parts.length>1){ parts.reverse(); add(parts.join(' ').replace(/\s+([?.!,;:])/g,'$1')); } else break; }
  return [correct,...chosen.slice(0,2)].sort(()=>Math.random()-0.5); }
function splitTokens(fr){ return fr.replace(/([?.!,;:])/g,' $1').split(/\s+/).filter(Boolean); }
function makeWordOrderQuestion(fr,i){ return splitTokens(fr).map((word,idx)=>({word,id:`${i}-${idx}-${word}`})).sort(()=>Math.random()-0.5); }

function cleanPracticeLead(en, fr){
  const enLeads=[
    ['For this exercise, ',''], ['In this situation, ',''], ['During the activity, ',''], ['During this activity, ',''], ['For this practice, ',''], ['In this example, ',''],
    ['After lunch, ',''], ['Tomorrow, ',''], ['Today, ','']
  ];
  const frLeads=[
    ['Pour cet exercice, ',''], ['Dans cette situation, ',''], ["Pendant l'activité, ",''], ['Pendant cette activité, ',''], ['Pour cette pratique, ',''], ['Dans cet exemple, ',''],
    ['Après le déjeuner, ',''], ['Demain, ',''], ["Aujourd'hui, ",'']
  ];
  let outEn=en || '', outFr=fr || '';
  enLeads.forEach(([a,b])=>{ if(outEn.startsWith(a)) outEn=b+outEn.slice(a.length); });
  frLeads.forEach(([a,b])=>{ if(outFr.startsWith(a)) outFr=b+outFr.slice(a.length); });
  outEn = outEn.charAt(0).toUpperCase() + outEn.slice(1);
  outFr = outFr.charAt(0).toUpperCase() + outFr.slice(1);
  return {en:outEn, fr:outFr};
}
function addNaturalContext(pair, i){
  const contexts=[
    ['At work, ', 'Au travail, '],
    ['This week, ', 'Cette semaine, '],
    ['In the morning, ', 'Le matin, '],
    ['With my family, ', 'Avec ma famille, '],
    ['At the station, ', 'À la gare, '],
    ['In class, ', 'En classe, '],
    ['At home, ', 'À la maison, '],
    ['Before the meeting, ', 'Avant la réunion, '],
    ['In my city, ', 'Dans ma ville, '],
    ['On Saturday, ', 'Samedi, ']
  ];
  let {en,fr}=cleanPracticeLead(pair.en,pair.fr);
  const [cen,cfr]=contexts[i % contexts.length];
  // Avoid adding a context when the sentence is already a question or already has a natural leading time/place phrase.
  if(!en.includes('?') && !/^(At|In|On|Before|After|With|This|Today|Tomorrow|Yesterday|When|If)\b/i.test(en)){
    en = cen + en.charAt(0).toLowerCase() + en.slice(1);
    fr = cfr + fr.charAt(0).toLowerCase() + fr.slice(1);
  }
  return {en,fr};
}
function getPracticeSentences(lesson){
  let base = Array.isArray(lesson.practiceSentences) && lesson.practiceSentences.length ? lesson.practiceSentences : lesson.sentences;
  base = (base || []).map((p,i)=>addNaturalContext(p,i));
  // If old generated practice is too repetitive, mix in adapted sentence-bank items to keep the practice alive and varied.
  if(base.length < 10 && Array.isArray(lesson.sentences)){
    base = base.concat(lesson.sentences.map((p,i)=>addNaturalContext(p,i+base.length)));
  }
  // Remove duplicates and empty items.
  const seen=new Set();
  const clean=[];
  for(const p of base){
    if(!p || !p.en || !p.fr) continue;
    const key=normalizeAnswer(p.en+' '+p.fr);
    if(seen.has(key)) continue;
    seen.add(key); clean.push(p);
  }
  return clean.slice(0,10);
}

function chooseBlankWord(fr){
  const skip = new Set(['je','j','tu','il','elle','nous','vous','ils','elles','le','la','les','un','une','des','du','de','d','au','aux','et','ou','mais','donc','car','que','qui','où','dont','à','en','dans','sur','pour','avec','sans','ce','cet','cette','ces','mon','ma','mes','ton','ta','tes','son','sa','ses','notre','votre','leur','leurs','pas','ne','n','est','sont','a','ont','ai','as','avons','avez','vais','va','allons','allez','vont']);
  const tokens = splitTokens(fr);
  const candidates = tokens.map((w,i)=>({w,i,clean:w.toLowerCase().replace(/[’']/g,"'").replace(/[^a-zàâçéèêëîïôùûüÿñæœ'-]/gi,'')}))
    .filter(x=>x.clean.length>=4 && !skip.has(x.clean.replace(/^l'|^d'|^j'|^n'|^s'|^qu'/,'')) && !/[?.!,;:]/.test(x.w));
  if(candidates.length){
    candidates.sort((a,b)=>b.clean.length-a.clean.length);
    return candidates[Math.min(1,candidates.length-1)];
  }
  const fallback=tokens.findIndex(w=>w.length>2 && !/[?.!,;:]/.test(w));
  return {w: tokens[fallback>=0?fallback:0] || '', i: fallback>=0?fallback:0};
}
function blankFrench(fr){
  const tokens=splitTokens(fr);
  if(!tokens.length) return {before:'',answer:'',after:'',full:fr};
  const pick=chooseBlankWord(fr);
  const answer=pick.w;
  tokens[pick.i]='__________';
  const blanked=tokens.join(' ').replace(/\s+([?.!,;:])/g,'$1');
  const parts=blanked.split('__________');
  return {before:parts[0]||'', answer, after:parts.slice(1).join('__________')||'', full:fr};
}
function mutateWord(word, mode){
  const accents = {'é':'e','è':'e','ê':'e','à':'a','ç':'c','ù':'u','î':'i','ô':'o'};
  let w=word;
  if(mode===0){
    for(const [a,b] of Object.entries(accents)){ if(w.includes(a)) return w.replace(a,b); }
    return w.length>3 ? w.slice(0,-1) : w+'e';
  }
  if(mode===1){
    return w.length>4 ? w.slice(0,-2)+w.slice(-1) : w+'s';
  }
  if(mode===2){
    if(w.length>3){ const i=Math.max(1,Math.floor(w.length/2)-1); return w.slice(0,i)+w[i+1]+w[i]+w.slice(i+2); }
    return w+'r';
  }
  return w.length>4 ? w+'e' : w+'t';
}
function spellingOptions(answer){
  const set=new Set([answer]);
  let mode=0;
  while(set.size<4 && mode<12){
    const v=mutateWord(answer, mode%4);
    if(normalizeAnswer(v)!==normalizeAnswer(answer)) set.add(v);
    mode++;
  }
  while(set.size<4) set.add(answer + (set.size===1?'e':set.size===2?'s':'t'));
  return Array.from(set).sort(()=>Math.random()-0.5);
}

function renderPractice(lesson){
  const practice=getPracticeSentences(lesson);
  if(!practice.length){ return `<article class="exercise-card"><h3 class="section-title"><span>🎯</span> Practice</h3><p class="muted">Practice is loading. Please reopen this class or refresh the app.</p></article>`; }
  const choiceQuestions=practice.slice(0,5).map((s,i)=>({...s,choices:makeChoiceOptions(s,i),answer:s.fr}));
  const fillQuestions=practice.slice(5,8).map(s=>({...blankFrench(s.fr),en:s.en,full:s.fr}));
  const orderQuestions=practice.map((s,i)=>({...s,tokens:makeWordOrderQuestion(s.fr,i)}));
  return `<article class="exercise-card"><h3 class="section-title"><span>🎯</span> A. Quick choose</h3><p class="muted">Choose the correct French sentence. The wrong options are close, but they contain a real grammar or word-order mistake.</p>${choiceQuestions.map((q,qi)=>`<div class="translation-row" data-qtype="choice" data-answer="${escapeHtml(q.answer)}" data-en="${escapeHtml(q.en)}"><strong>${qi+1}. ${escapeHtml(q.en)}</strong><div class="choice-grid">${q.choices.map(choice=>`<button class="choice-btn" type="button" data-choice="${escapeHtml(choice)}" data-answer="${escapeHtml(q.answer)}">${escapeHtml(choice)}</button>`).join('')}</div><div class="feedback"></div></div>`).join('')}</article>
<article class="exercise-card"><h3 class="section-title"><span>✍️</span> B. Fill in the blank</h3><p class="muted">Type the missing French word. If the spelling is not correct, choose the right spelling from four similar options.</p>${fillQuestions.map((q,i)=>`<div class="translation-row fill-row" data-qtype="fill" data-answer="${escapeHtml(q.answer)}" data-full="${escapeHtml(q.full)}" data-en="${escapeHtml(q.en)}"><strong>${i+1}. ${escapeHtml(q.en)}</strong><div class="french">${escapeHtml(q.blanked)}</div><input type="text" class="fill-input" data-answer="${escapeHtml(q.answer)}" placeholder="Missing word" /><button class="check-btn" type="button" data-check-fill>Check</button><div class="feedback"></div><div class="spelling-options" hidden></div></div>`).join('')}</article>
<article class="exercise-card"><h3 class="section-title"><span>🧩</span> C. Word order challenge</h3><p class="muted">Translate each English sentence by putting the French words in the correct order. These are practice sentences, not exact copies from the sentence bank.</p>${orderQuestions.map((s,i)=>`<div class="translation-row word-order-row" data-qtype="order" data-order-answer="${escapeHtml(s.fr)}" data-en="${escapeHtml(s.en)}"><strong>${i+1}. ${escapeHtml(s.en)}</strong><div class="word-bank">${s.tokens.map(token=>`<button class="word-chip" type="button" data-word="${escapeHtml(token.word)}" data-token-id="${escapeHtml(token.id)}">${escapeHtml(token.word)}</button>`).join('')}</div><div class="answer-bank"><span class="placeholder">Tap words above to build your answer.</span></div><div class="sentence-actions"><button class="speech-btn" type="button" data-speak="${escapeHtml(s.fr)}" data-rate="0.86">🔊 Listen</button><button class="speech-btn slow-btn" type="button" data-speak="${escapeHtml(s.fr)}" data-rate="0.5">🐢 Slow 0.5x</button><button class="ghost-btn" type="button" data-reset-order>Reset</button><button class="check-btn" type="button" data-check-order>Check sentence</button></div><div class="feedback"></div><div class="answer-reveal">Answer: ${escapeHtml(s.fr)}</div></div>`).join('')}
<div class="score-card"><strong>Practice score</strong><div id="practiceScore" class="score-result">Score not checked yet.</div><div id="mistakeReview"></div><div class="sentence-actions"><button class="primary-btn" type="button" id="checkPracticeScore">Check practice score</button><button class="ghost-btn" type="button" id="showAnswers">Show answers</button><button class="primary-btn" type="button" id="completeClass" disabled>Complete class and unlock next</button></div><article class="lesson-card next-preview"><h3 class="section-title"><span>➡️</span> Next class preview</h3><p>${escapeHtml(lesson.nextPreview || '')}</p></article></div></article>`;
}
function renderExam(lesson){ if(!lesson.exam || !lesson.exam.length) return `<article class="lesson-card"><h3>No exam for this class</h3><p>This class has normal practice only.</p></article>`; return `<article class="lesson-card"><h3 class="section-title"><span>📝</span> Block exam</h3><p class="muted">Complete the exam in writing or orally. Use the answer key only after trying.</p><div class="exam-box">${escapeHtml(lesson.exam.join('\n\n'))}</div></article>`; }
function bindDynamicActions(root,lesson){
  $$('[data-speak]',root).forEach(btn=>btn.addEventListener('click',()=>speakFrench(btn.dataset.speak, Number(btn.dataset.rate||0.86))));
  $$('[data-reveal-sentence]',root).forEach(btn=>btn.addEventListener('click',()=>{ btn.classList.add('revealed'); const actions=btn.parentElement.querySelector('.reveal-actions'); if(actions) actions.hidden=false; }));
  $$('[data-choice]',root).forEach(btn=>btn.addEventListener('click',()=>{ const row=btn.closest('.translation-row'); const buttons=$$('.choice-btn',row); buttons.forEach(b=>{b.disabled=true;b.dataset.selected='false';}); btn.dataset.selected='true'; const ok=normalizeAnswer(btn.dataset.choice)===normalizeAnswer(btn.dataset.answer); btn.classList.add(ok?'correct':'wrong'); buttons.find(b=>normalizeAnswer(b.dataset.choice)===normalizeAnswer(btn.dataset.answer))?.classList.add('correct'); const f=$('.feedback',row); f.textContent=ok?'Correct!':'Not yet. Compare the highlighted correction.'; f.className=`feedback ${ok?'ok':'no'}`; vibrate(); }));
  $$('[data-check-fill]',root).forEach(btn=>btn.addEventListener('click',()=>{ const row=btn.closest('.fill-row'); const input=$('.fill-input',row); const feedback=$('.feedback',row); const answer=input.dataset.answer; const ok=normalizeAnswer(input.value)===normalizeAnswer(answer); if(ok){ row.dataset.fillCorrect='true'; feedback.textContent='Correct!'; feedback.className='feedback ok'; $('.spelling-options',row).hidden=true; } else { row.dataset.fillCorrect='false'; feedback.textContent='Almost. Now choose the correct spelling.'; feedback.className='feedback no'; const box=$('.spelling-options',row); box.hidden=false; box.innerHTML=spellingOptions(answer).map(opt=>`<button class="spelling-option" type="button" data-spelling="${escapeHtml(opt)}" data-answer="${escapeHtml(answer)}">${escapeHtml(opt)}</button>`).join(''); $$('.spelling-option',box).forEach(optBtn=>optBtn.addEventListener('click',()=>{ const good=normalizeAnswer(optBtn.dataset.spelling)===normalizeAnswer(answer); $$('.spelling-option',box).forEach(b=>b.disabled=true); optBtn.classList.add(good?'correct':'wrong'); $$('.spelling-option',box).find(b=>normalizeAnswer(b.dataset.spelling)===normalizeAnswer(answer))?.classList.add('correct'); row.dataset.fillCorrect=good?'true':'false'; feedback.textContent=good?'Correct on the spelling step!':`The correct spelling is: ${answer}`; feedback.className=`feedback ${good?'ok':'no'}`; })); } }));
  $$('.word-chip',root).forEach(btn=>btn.addEventListener('click',()=>{ const row=btn.closest('.word-order-row'); const bank=$('.answer-bank',row); $('.placeholder',bank)?.remove(); btn.disabled=true; const chosen=document.createElement('button'); chosen.type='button'; chosen.className='chosen-chip'; chosen.dataset.word=btn.dataset.word; chosen.dataset.tokenId=btn.dataset.tokenId; chosen.textContent=btn.dataset.word; chosen.addEventListener('click',()=>{ const orig=$(`.word-chip[data-token-id="${chosen.dataset.tokenId}"]`,row); if(orig) orig.disabled=false; chosen.remove(); if($$('.chosen-chip',bank).length===0) bank.innerHTML='<span class="placeholder">Tap words above to build your answer.</span>'; }); bank.appendChild(chosen); const f=$('.feedback',row); f.textContent=''; f.className='feedback'; vibrate(); }));
  $$('[data-reset-order]',root).forEach(btn=>btn.addEventListener('click',()=>resetOrderRow(btn.closest('.word-order-row'))));
  $$('[data-check-order]',root).forEach(btn=>btn.addEventListener('click',()=>checkWordOrderRow(btn.closest('.word-order-row'),true)));
  const check=$('#checkPracticeScore',root); if(check) check.addEventListener('click',()=>handleScore(root,lesson));
  const show=$('#showAnswers',root); if(show) show.addEventListener('click',()=>$$('.answer-reveal',root).forEach(a=>a.classList.add('show')));
  const complete=$('#completeClass',root); if(complete) complete.addEventListener('click',()=>{ const scoreBox=$('#practiceScore',root); if(complete.disabled) return; const currentScore = state.scores[state.level][lesson.id] || {}; currentScore.completed=true; state.scores[state.level][lesson.id]=currentScore; markCompleted(state.level,lesson.id); saveState(); showToast(`${state.level} Class ${lesson.id} completed. Next class unlocked.`); setupSelector(); render(); });
}
function resetOrderRow(row){ if(!row) return; $$('.word-chip',row).forEach(c=>c.disabled=false); $('.answer-bank',row).innerHTML='<span class="placeholder">Tap words above to build your answer.</span>'; const f=$('.feedback',row); f.textContent=''; f.className='feedback'; row.dataset.orderCorrect='false'; $('.answer-reveal',row)?.classList.remove('show'); }
function checkWordOrderRow(row,showFeedback){ const built=$$('.chosen-chip',row).map(x=>x.dataset.word).join(' '); const expected=row.dataset.orderAnswer; const ok=normalizeAnswer(built)===normalizeAnswer(expected); row.dataset.orderCorrect=ok?'true':'false'; if(showFeedback){ const f=$('.feedback',row); f.textContent=ok?'Correct!':'Not yet. Try the order again, or show the answer after you try.'; f.className=`feedback ${ok?'ok':'no'}`; } return ok; }
function collectScore(root){ let correct=0,total=0,wrongs=[]; $$('.translation-row[data-qtype="choice"]',root).forEach(row=>{ total++; const selected=$('[data-choice][data-selected="true"]',row); const ans=row.dataset.answer; if(selected && normalizeAnswer(selected.dataset.choice)===normalizeAnswer(ans)) correct++; else wrongs.push({type:'choice', en:row.dataset.en, fr:ans}); }); $$('.fill-row',root).forEach(row=>{ total++; if(row.dataset.fillCorrect==='true') correct++; else wrongs.push({type:'fill', en:row.dataset.en, fr:row.dataset.full || row.dataset.answer}); }); $$('.word-order-row',root).forEach(row=>{ total++; if(checkWordOrderRow(row,false)) correct++; else wrongs.push({type:'order', en:row.dataset.en, fr:row.dataset.orderAnswer}); }); return {correct,total,wrongs}; }
function handleScore(root,lesson){ const result=collectScore(root); const pct=result.total?Math.round(result.correct/result.total*100):0; const box=$('#practiceScore',root); box.textContent=`Score: ${result.correct} / ${result.total} (${pct}%)`; box.className=`score-result ${pct>=80?'ok':pct>=50?'mid':'no'}`; state.scores[state.level][lesson.id]={correct:result.correct,total:result.total,percent:pct,completed:false,date:new Date().toISOString()}; saveState(); const review=$('#mistakeReview',root); const complete=$('#completeClass',root); if(result.wrongs.length){ review.innerHTML=renderMistakeReview(result.wrongs); bindMistakeReview(review,complete); complete.disabled=true; } else { review.innerHTML='<div class="feedback ok">Excellent. No mistakes to review. You can complete this class and unlock the next one.</div>'; complete.disabled=false; } const s=totalScore(state.level); $('#totalScore').textContent=`Total score: ${s.correct} / ${s.total}`; showToast(`Practice checked: ${result.correct} / ${result.total}`); }
function renderMistakeReview(wrongs){ return `<section class="mistake-review"><h3 class="section-title"><span>🔄</span> Review your mistakes</h3><p class="muted">Before you unlock the next class, redo only the sentences you missed. Put the French words in the correct order.</p>${wrongs.map((w,i)=>{ const tokens=makeWordOrderQuestion(w.fr,i+90); return `<div class="translation-row remedial-row" data-order-answer="${escapeHtml(w.fr)}"><strong>${i+1}. ${escapeHtml(w.en)}</strong><div class="word-bank">${tokens.map(t=>`<button class="word-chip remedial-chip" type="button" data-word="${escapeHtml(t.word)}" data-token-id="r-${escapeHtml(t.id)}">${escapeHtml(t.word)}</button>`).join('')}</div><div class="answer-bank"><span class="placeholder">Tap words to rebuild the correction.</span></div><div class="sentence-actions"><button class="ghost-btn" type="button" data-reset-remedial>Reset</button><button class="check-btn" type="button" data-check-remedial>Check correction</button></div><div class="feedback"></div></div>`; }).join('')}</section>`; }
function bindMistakeReview(root,completeBtn){ $$('.remedial-chip',root).forEach(btn=>btn.addEventListener('click',()=>{ const row=btn.closest('.remedial-row'); const bank=$('.answer-bank',row); $('.placeholder',bank)?.remove(); btn.disabled=true; const c=document.createElement('button'); c.type='button'; c.className='chosen-chip'; c.dataset.word=btn.dataset.word; c.dataset.tokenId=btn.dataset.tokenId; c.textContent=btn.dataset.word; c.addEventListener('click',()=>{ const orig=$(`.remedial-chip[data-token-id="${c.dataset.tokenId}"]`,row); if(orig) orig.disabled=false; c.remove(); if($$('.chosen-chip',bank).length===0) bank.innerHTML='<span class="placeholder">Tap words to rebuild the correction.</span>'; }); bank.appendChild(c); })); $$('[data-reset-remedial]',root).forEach(btn=>btn.addEventListener('click',()=>{ const row=btn.closest('.remedial-row'); $$('.remedial-chip',row).forEach(c=>c.disabled=false); $('.answer-bank',row).innerHTML='<span class="placeholder">Tap words to rebuild the correction.</span>'; const f=$('.feedback',row); f.textContent=''; f.className='feedback'; row.dataset.correct='false'; })); $$('[data-check-remedial]',root).forEach(btn=>btn.addEventListener('click',()=>{ const row=btn.closest('.remedial-row'); const built=$$('.chosen-chip',row).map(x=>x.dataset.word).join(' '); const ok=normalizeAnswer(built)===normalizeAnswer(row.dataset.orderAnswer); row.dataset.correct=ok?'true':'false'; const f=$('.feedback',row); f.textContent=ok?'Correct. Mistake fixed.':'Not yet. Rebuild the correction carefully.'; f.className=`feedback ${ok?'ok':'no'}`; const all=$$('.remedial-row',root).every(r=>r.dataset.correct==='true'); if(all){ completeBtn.disabled=false; showToast('Mistake review completed. You can unlock the next class.'); } })); }
document.addEventListener('DOMContentLoaded',()=>{ initTelegram(); bindStaticActions(); setTheme(state.theme); setupSelector(); render(); if('speechSynthesis' in window) window.speechSynthesis.onvoiceschanged=()=>{}; });
